import sys

def solve(n, a):
    a.sort()
    c = 1
    while True:
        for i in range(n):
            if a[i] != c ** i:
                return False
        if c == 1:
            return True
        c -= 1
    return True

def main():
    n = int(sys.stdin.readline())
    a = list(map(int, sys.stdin.readline().split()))
    if solve(n, a):
        print("Yes")
    else:
        print("No")

if __name__ == "__main__":
    main()
